// Structure to hold the results 
#[derive(Default)]
#[derive(Debug)]
pub struct Atom {
    atom_id: usize,
    atom_symbol: String,
    is_aromatic: bool,
    is_in_bracket: bool, 
    has_hs: bool, 
    isotopic_number: usize,
    chirality: String,
    n_hs: u8,
    charge: i8,
    class: String
}
#[derive(Default)]
#[derive(Debug)]
pub struct Bond {
    bond_id: String,
    atom_one: usize,
    atom_two: usize,
    bond_symbol: String
}
#[derive(Default)]
#[derive(Debug)]
pub struct Structure {
    atoms:              Vec<Atom>,
    bonds:              Vec<Bond>,
    symbols:            BTreeMap<usize, String>,
    input_smiles:       String,
    status:             bool,
    error:              String
}


  ///////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////
 // Add implementation of the JSON conversion to the struct describing Structure - impl is enough, since only this struct needs it    //
///////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

impl Structure {
  fn get_json(&self) -> String {
    let mut json_string = String::from("{'atoms': [");
    // Structure is a forest:
    // start from atoms and create, like, {"atoms": [{...}, ..., {...}],
    // proceed with bonds: {"atoms": [{...}, ..., {...}], "bonds": [{...}, ..., {...}],
    // proceed with symbols: {"atoms": [{...}, ..., {...}], "bonds": [{...}, ..., {...}], "symbols": [...],
    // add input SMILES: {"atoms": [{...}, ..., {...}], "bonds": [{...}, ..., {...}], "symbols": [...], "smiles": '',
    // add status: {"atoms": [{...}, ..., {...}], "bonds": [{...}, ..., {...}], "symbols": [...], "smiles": '', "status": '',
    // add an error if any and finalize the string: {"atoms": [{...}, ..., {...}], "bonds": [{...}, ..., {...}], "symbols": [...], "smiles": '', "status": '', "error": ''}
    // ...

     //
    // ATOMS
   //

    for atom in &self.atoms {
      println!("new atom encountered");
      json_string.push_str("{'atom_id': ");
      json_string.push_str(atom.atom_id.to_string().as_str());
      json_string.push_str(", 'atom_symbol': ");
      json_string.push_str(atom.atom_symbol.as_str());
      json_string.push_str(", 'is_aromatic': ");
      json_string.push_str(atom.is_aromatic.to_string().as_str());
      json_string.push_str(", 'is_in_bracket': ");
      json_string.push_str(atom.is_in_bracket.to_string().as_str());
      json_string.push_str(", 'has_hs': ");
      json_string.push_str(atom.has_hs.to_string().as_str());
      json_string.push_str(", 'isotopic_number': ");
      json_string.push_str(atom.isotopic_number.to_string().as_str());
      json_string.push_str(", 'chirality': ");
      json_string.push_str(atom.chirality.to_string().as_str());
      json_string.push_str(", 'n_hs': ");
      json_string.push_str(atom.n_hs.to_string().as_str());
      json_string.push_str(", 'charge': ");
      json_string.push_str(atom.charge.to_string().as_str());
      json_string.push_str(", 'class': ");
      json_string.push_str(atom.class.as_str());
      json_string.push_str("}, ");
    }
    json_string.pop();
    json_string.pop();
    json_string.push_str("], ");

     //
    // BONDS
   //

    json_string.push_str("'bonds': [");
    for bond in &self.bonds {
      println!("new bond encountered");
      json_string.push_str("{'bond_id': ");
      json_string.push_str(bond.bond_id.as_str());
      json_string.push_str(", 'atom_one': ");
      json_string.push_str(bond.atom_one.to_string().as_str());
      json_string.push_str(", 'atom_two': ");
      json_string.push_str(bond.atom_two.to_string().as_str());
      json_string.push_str(", 'bond_symbol': ");
      json_string.push_str(bond.bond_symbol.to_string().as_str());
      json_string.push_str("}, ");
    }

     //
    // SYMBOLS
   //

    json_string.push_str("'symbols': [");
    for symbol in &self.symbols.values().collect::<Vec<_>>() {
      println!("new symbol encountered");
      json_string.push_str(", 'symbol': ");
      json_string.push_str(symbol);
      json_string.push_str("}, ");
    }
    json_string.pop();
    json_string.pop();
    json_string.push_str("], ");

     //
    // STATUS
   //

    json_string.push_str("'status': ");
    json_string.push_str(&self.status.to_string().as_str());
    json_string.push_str(", 'error': ");
    json_string.push_str(&self.error.to_string().as_str());
    json_string.push_str("}, ");
    // Return the string
    json_string
  }
}

