// Function to parse SMILES
pub fn parse_smiles(ps_smiles_string: &String, mut ps_structure: Structure) -> Structure {
  // Initial state
  ps_structure.status = true;
  // Count symbols to work with them latter
  let mut symbol_number:  usize = 0;
  // Count the total length of the SMILES string in characters
  let ps_n_all:           usize = ps_smiles_string.chars().count() as usize;
  let mut ps_position:    usize = 0;
  let mut ps_chunk: &str = "";
  let mut ps_symbol: String = String::from("");
  let mut ps_simple_ct_on: bool = false;
  // Remember the order of properties
  // 0 - no open bracket
  // 1 - open bracket
  // 2 - isotope
  // 3 - atom
  // 4 - chirality
  // 5 - hydro
  // 6 - charge
  // 7 - class
  let mut ps_inbracket:     usize = 0;
  let mut ps_last_symbol:   usize = 0;
  let mut ps_next_position: usize = 0;
  let mut ps_prev_symbol:   String = "".to_string();

  // Parse SMILES in a loop, v1 chunk it
  while ps_n_all > ps_position {
      // Get this chunk
      ps_chunk = get_chunk(ps_smiles_string, ps_position, 5);
      // Test
      //println!("{:?}", ps_chunk);

      // Get this symbol
      ps_symbol = get_symbol(ps_chunk, &SYMBOLONE, &SYMBOLTWO, &SYMBOLTHREE, &SYMBOLFOUR, &SYMBOLFIVE);

      // Increase the symbol number
      symbol_number = symbol_number + 1;

      // Insert the symbol
      ps_structure.symbols.insert(symbol_number, ps_symbol.clone());

      // Update position according to the symbol length
      ps_position = (ps_position + 5) - (5 - ps_symbol.len());

      // Update state
      if ps_position >= ps_n_all {
          ps_last_symbol = 1;
      }

      // Update structure
      ps_structure = update(ps_structure, &ps_symbol, ps_prev_symbol,
                                      ps_simple_ct_on, ps_inbracket, ps_last_symbol, symbol_number);

      // Check updated structure
      if ps_structure.status == false {
          return ps_structure;
      }

      // Finally, update the previous symbol
      ps_prev_symbol = ps_symbol.clone();
  }

  // Output
  return ps_structure;
}